from dataclasses import dataclass, field

@dataclass
class TenantResidencyConfig:
    tenant_id: str
    default_data_subject_region: DataRegion
    allowed_regions: list[DataRegion]
    require_eu_endpoint_for_eu_data: bool = True
    require_cn_endpoint_for_cn_data: bool = True
    deny_cross_region_without_tia: bool = True
    tia_approved_regions: list[DataRegion] = field(default_factory=list)

    def effective_region(self, hint: DataRegion | None = None) -> DataRegion:
        """Resolve the effective data subject region for a request."""
        if hint and hint in self.allowed_regions:
            return hint
        return self.default_data_subject_region

    def cross_region_allowed(self,
                             data_region: DataRegion,
                             endpoint_region: DataRegion) -> bool:
        if data_region == endpoint_region:
            return True
        if not self.deny_cross_region_without_tia:
            return True
        return endpoint_region in self.tia_approved_regions
